/**
 * @param {number[]} nums
 * @param {number[][]} queries
 * @return {number[]}
 */
function solve(nums, queries) {
    const results = [];

    for (const query of queries) {
        const [l, r, k] = query;

        // 1. Identify all positive even numbers in nums[l..r]
        let removedEvens = new Set();
        for (let i = l; i <= r; i++) {
            const num = nums[i];
            if (num % 2 === 0) {
                removedEvens.add(num);
            }
        }

        // 2. Find the k-th smallest remaining positive even number.
        // The sequence of all positive even numbers is: 2, 4, 6, 8, 10, 12, ...
        // The n-th positive even number is 2 * n.

        // We are looking for the k-th number in the sequence (2, 4, 6, ...) \ RemovedEvens.

        // Let's consider a target even number, T = 2 * N.
        // The number of positive even integers less than or equal to T is N.
        // The number of removed even integers less than or equal to T is the count of 
        // elements in removedEvens that are <= T.

        // If T is the answer, then:
        // (Count of evens <= T) - (Count of removed evens <= T) = k
        // N - (Count of removed evens <= T) = k
        // N = k + (Count of removed evens <= T)

        // Since T = 2N, we are looking for the smallest T such that the count condition holds.

        // The maximum possible value for the answer is related to k + |removedEvens|.
        // Since k <= 10^9 and |removedEvens| <= 10^5, the answer is around 2 * (10^9 + 10^5).
        // We can use binary search on the possible answer T (or equivalently, on N = T/2).

        // Max possible N: k + (number of evens in nums) which is at most 10^9 + 10^5.
        let lowN = 1;
        // A safe upper bound for N. Max k is 10^9. Max removed count is 10^5.
        // N_max ~ 10^9 + 10^5. Let's use 2 * 10^9 + 200000 for safety.
        let highN = 2000000000 + 200000; 
        let ansN = highN;

        // Count the number of removed evens up to a certain value `upperBound`.
        const countRemovedUpTo = (upperBound) => {
            let count = 0;
            for (const removed of removedEvens) {
                if (removed <= upperBound) {
                    count++;
                }
            }
            return count;
        };

        // Binary Search for N such that N - countRemovedUpTo(2*N) >= k, and we seek the smallest such N.
        while (lowN <= highN) {
            const midN = Math.floor((lowN + highN) / 2);
            const T = 2 * midN;

            const removedCount = countRemovedUpTo(T);

            // The rank of T (if it wasn't removed) is midN.
            // The actual rank of T in the remaining sequence is midN - removedCount.
            const rank = midN - removedCount;

            if (rank >= k) {
                // T might be the answer, or we can find a smaller one.
                ansN = midN;
                highN = midN - 1;
            } else {
                // T is too small, need a larger T.
                lowN = midN + 1;
            }
        }

        // The smallest N found (ansN) gives the smallest T = 2*ansN such that the rank is >= k.
        // We must ensure that the T corresponding to ansN is indeed the k-th element.

        // The smallest N such that N - countRemovedUpTo(2N) >= k is the required N.
        // Let N_final = ansN. T_final = 2 * N_final.
        // Rank of T_final is N_final - countRemovedUpTo(2*N_final). This rank >= k.

        // If the rank is exactly k, T_final is the answer.
        // If the rank is > k, it means the k-th element is smaller than T_final, which contradicts 
        // the binary search finding the smallest N that satisfies the condition.

        // The binary search guarantees that ansN is the smallest integer such that:
        // ansN - countRemovedUpTo(2 * ansN) >= k

        // Let's check the element immediately before T_final, i.e., 2*(ansN - 1).
        // Rank of 2*(ansN - 1) is (ansN - 1) - countRemovedUpTo(2*(ansN - 1)).
        // By the property of BS, this rank must be < k.

        // Therefore, the k-th element must be 2 * ansN.

        const finalAnswer = 2 * ansN;
        results.push(finalAnswer);
    }

    return results;
}

