package main

func solve(nums []int64, queries [][]int64) []int64 {
	results := make([]int64, len(queries))

	for i, query := range queries {
		l := query[0]
		r := query[1]
		k := query[2]

		// 1. Identify all positive even numbers in nums[l..r]
		removedEvensMap := make(map[int64]bool)
		for j := l; j <= r; j++ {
			num := nums[j]
			if num%2 == 0 {
				removedEvensMap[num] = true
			}
		}

		// Extract removed evens into a sorted slice for efficient counting
		var removedEvens []int64
		for num := range removedEvensMap {
			removedEvens = append(removedEvens, num)
		}
		// Since nums is strictly increasing, the evens encountered will naturally be sorted, 
		// but we sort explicitly to be safe with the map iteration order.
		// Since nums[i] <= 10^9, this is fine.
		// However, since we only care about *which* evens are present, the map is sufficient, 
		// but sorting them helps in counting efficiently in the binary search.
		// Since the number of evens is small (<= 10^5), sorting is fast enough.
		// Using a map and then iterating over it in the count function is O(E), where E is number of removed evens.
		// We stick to the map approach for simplicity unless performance dictates otherwise.

		// Count the number of removed evens up to a certain value `upperBound`.
		// This function runs O(E) where E is |removedEvensMap|.
		countRemovedUpTo := func(upperBound int64) int64 {
			count := int64(0)
			for num := range removedEvensMap {
				if num <= upperBound {
					count++
				}
			}
			return count
		}

		// Binary Search for N such that N - countRemovedUpTo(2*N) >= k, and we seek the smallest such N.
		// T = 2*N is the candidate answer.

		// k <= 10^9. Number of removed evens <= 10^5.
		// Max N needed is roughly k + |removedEvens| ~ 10^9 + 10^5.

		lowN := int64(1)
		// Safe upper bound: 2 * (10^9 + 10^5) is around 2*10^9. Using 3*10^9 for extreme safety.
		highN := int64(3000000000) 
		ansN := highN

		for lowN <= highN {
			midN := lowN + (highN-lowN)/2
			T := 2 * midN

			removedCount := countRemovedUpTo(T)

			// Rank = (Total evens <= T) - (Removed evens <= T)
			// Total evens <= T is midN.
			rank := midN - removedCount

			if rank >= k {
				// T might be the answer, or we can find a smaller one.
				ansN = midN
				highN = midN - 1
			} else {
				// T is too small, need a larger T.
				lowN = midN + 1
			}
		}

		// The smallest N found (ansN) yields the k-th smallest element 2*ansN.
		results[i] = 2 * ansN
	}

	return results
}
